import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        String userInput = request.getParameter("input");
        String safeUserInput = sanitizeInput(userInput);

        out.println("<html><body>");
        out.println("User Input: " + safeUserInput); // Display sanitized user input
        out.println("</body></html>");
    }

    private String sanitizeInput(String input) {
        // Replace potentially harmful characters with their HTML entities
        return input != null ? input.replace("&", "&amp;")
                                    .replace("<", "&lt;")
                                    .replace(">", "&gt;")
                                    .replace("\"", "&quot;")
                                    .replace("'", "&#39;") : "";
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
